```

3d
```{r}
prediction <- function(x){
  if (x > 0 & x < 15){
      y = 6 + 0.8 * x
  } else if (x > 15 & x < 30) {
      y = 5 + 0.75 * x
  } else {
      y = NA
  }
  return (y)
}
```

