```{r}
prediction <- function(x){
  if (x > 0 & x < 15){
      y = 6 + 0.8 * x
  } else if (x > 15 & x < 30) {
      y = 5 + 0.75 * x
  } else {
      y = NA
  }
  return (y)
}
```

3e
```{r}
prediction(5)
```

3f
```{r}
prediction(26)
```

3g
```{r}
prediction(-2)
```

### 4. Size Estimates by Name (20 points)

```{r}
get_mass_from_length <- function(a, b, length){
  mass = a * length ** b
  return (mass)
}

get_mass_from_length_by_name <- function(length, name){
  if (name == "Stegosauria"){
    if (length > 8){
      a = 10.95
      b = 2.64
    } else {
      a = 8.5
      b = 2.8
    }
  }
  else if (name == "Theropoda"){
    a = 0.73
    b = 3.63
  }
  else if (name == "Sauropoda"){
    a = 214.44
    b = 1.46
  }
  else {
    return(NA)
  }
  get_mass_from_length(a, b, length)
}
```

